// Helper functions
function color(text, color) {
  return `<span style="color:${color};">${text}</span>`;
}

function toWhole(num) {
  return Math.trunc(num);
}

function makeBar(percent, length = 20, color = "#22c55e") {
  percent = Math.max(0, Math.min(100, percent));
  let filled = Math.round((percent / 100) * length);
  let empty = length - filled;
  let bar = "";
  for (let i = 0; i < filled; i++) {
    bar += `<span style="color:${color};">█</span>`;
  }
  for (let i = 0; i < empty; i++) {
    bar += `<span style="color:#374151;">-</span>`;
  }
  return `[${bar}] ${percent}%`;
}

function separator(color = "#affc9f") {
  return `<span style="
    display:block;
    font-size:6px;
    line-height:8px;
    color:${color};
    letter-spacing:0px;
  ">─────────────────────────────────────────────────────────</span>`;
}

//====================
// SHARED CONTENT BUILDER
//====================
function buildTraxContent(showSections = null) {

  const data = gwc.gmcp.data.character;
  const name = data.status.name;

  let trax = gwc.userdata.trax || {};
  let us = gwc.userdata;

  let nl = "<br>";
  let sep = separator();

  function formatNumber(num) {
    if (num == null) return "0";
    return Number(num).toLocaleString();
  }

  //====================
  // ACTIVITY
  //====================

  let boarding = "";
  if(us.boardingnext && us.boardingnext === "true"){
    boarding = nl + color("Boarding next ship!" , colors.sep[0]);
  }

  let walks = "";
  if (trax.walks) {
    walks = nl + color("Rooms moved: ", colors.walk[0]) +
            color(formatNumber(trax.walks.alltime), colors.walk[1]);
  }

  let herbingt = "";
  let herbinga = "";
  if(trax.herbs && trax.herbs.today != 0){
    herbingt = nl + color("Herbs today: ", colors.herbs[0]) +
               color(formatNumber(trax.herbs.today), colors.herbs[1]);
  }
  if(trax.herbs && trax.herbs.alltime != 0){
    herbinga = nl + color("Herbs All Time: ", colors.herbs[0]) +
               color(formatNumber(trax.herbs.alltime), colors.herbs[1]);
  }

  let herbready = "";
  if(trax.caneatherb === true){
    herbready = nl + color("You can eat an herb", colors.herbs[1]);
  } else if(trax.caneatherb === false){
    herbready = nl + color("You cannot eat an herb" , colors.combat[1]);
  }

  let herbing = "";
  let path = us.currentPath;
  if (us.herbAliasName && us.herbscriptonoff == "on") {
    let herbPercent = toWhole((us.roomCounter / path.length) * 100);
    herbing =
      nl + color("Herbing: ", colors.herbs[0]) +
      color(makeBar(herbPercent, 16, colors.herbs[0]), colors.herbs[1]) +
      color(` (${us.roomCounter || 0}/${path.length})`, colors.herbs[1]);
  }

  let todayprog = "";
  if (trax.progress.today == 0){
    todayprog = nl + color("No progress made today" , colors.prog[0]);
  } else {
    todayprog = nl + color("Progress levels today: ", colors.prog[0]) +
                color(trax.progress.today, colors.prog[1]);
  }

  let fantaeq = toWhole(trax.progress.levels / 18);
  let progress =
    nl + color("All time progs: ",colors.prog[0]) +
    color(trax.progress.levels + " = " + fantaeq + " fantas", colors.prog[1]) +
    nl + color("All time fantastics: ",colors.prog[0]) +
    color(trax.progress.fantas, colors.prog[1]) +
    todayprog;

  //====================
  // COMBAT
  //====================

  let hunting = "";
  if(us.huntonoff){
    hunting = nl + color("Hunting is ", colors.combat[0]) +
              color(us.huntonoff, colors.combat[1]);
  }

  let tkills = "";
  if (trax.killz && trax.killz.today) {
    tkills = nl + color("Kills today: ", colors.combat[0]) +
             color(formatNumber(trax.killz.today), colors.combat[1]);
  }

  let akills = "";
  if (trax.killz && trax.killz.alltime) {
    akills = nl + color("Total kills: ", colors.combat[0]) +
             color(formatNumber(trax.killz.alltime), colors.combat[1]);
  }

  let huntprog = "";
  if (us.huntAliasName && us.huntonoff == "on") {
    let percent = toWhole((us.roomCounter / us.currentPath.length) * 100);
    let paused = us.huntpaused ? " (Paused)" : ` ${us.roomCounter}/${us.currentPath.length}`;

    huntprog =
      nl + color(
        "Hunting " + us.currentScript + ": " +
        color(makeBar(percent, 20, colors.combat[1]), colors.combat[0]) +
        paused,
        colors.combat[0]
      );
  }

  //====================
  // WORLDLY
  //====================

  let imbuesText = "";
  if (trax.imbues) {
    if (trax.imbues.alltime > 0) {
      imbuesText += nl + color("All-time imbues: ", colors.imbues[1]) +
                color(formatNumber(trax.imbues.alltime), colors.imbues[1]);
    }
    if (trax.imbues.session > 0) {
      imbuesText += nl + color("Session imbues: ", colors.imbues[1]) +
                color(formatNumber(trax.imbues.session), colors.imbues[1]);
    }
  }

  let coins = "";
  if (trax.coinloot) {
    coins =
      nl + color("Gold Looted: ", colors.worldly[1]) + color(formatNumber(trax.coinloot.gold || 0), colors.worldly[1]) +
      nl + color("Platinum Looted: ", colors.worldly[1]) + color(formatNumber(trax.coinloot.platinum || 0), colors.worldly[1]);
  }

  let bank = "";
  if (trax.bankacc) {
    bank = nl + color("Bank: ", colors.worldly[1]) +
           color(trax.bankacc + " platinum", colors.worldly[1]);
  }

  //====================
  // LEVEL + ABILITIES
  //====================

  let levelProg = "";
  if (trax.nextlevel) {
    levelProg =
      color(
        "Progress to " + (trax.nextlevel.rank || "?") + ": " +
        makeBar(trax.nextlevel.percent || 0),
        colors.prog[1]
      );
  }

  let strength = "";
  if(trax.canstrength === false){
    strength = nl + color("You cannot cast strength yet", colors.combat[1]);
  } else if(trax.canstrength === true){
    strength = nl + color("You can cast strength!" , colors.herbs[0]);
  }

  //====================
  // SECTION BUILDING
  //====================

  let WORLDLY =
    color("-- Worldly --", colors.worldly[0]) +
    bank + coins + imbuesText + sep;

  let ACTIVITY =
    color("-- Activity --", colors.sep[0]) +
    walks + boarding + progress + herbready + herbing + herbingt + herbinga + sep;

  let COMBAT =
    color("-- Combat --", colors.combat[0]) +
    hunting + huntprog + strength + akills + tkills + sep;

  // Apply tab filtering if provided
  if (showSections) {
    if (!showSections.worldly) WORLDLY = "";
    if (!showSections.activity) ACTIVITY = "";
    if (!showSections.combat) COMBAT = "";
  }

  //====================
  // FINAL HTML
  //====================

  return (
    sep +
    color(">---" + name + "---<", colors.sep[1]) + nl +
    color("Level: " + (data.status.level || 0), colors.sep[1]) + nl +
    levelProg +
    sep +
    WORLDLY +
    ACTIVITY +
    COMBAT
  );
}

