function populateStatusWindow() {
  if (!$('#' + statusWindowId).length) return;

  let $content = $('#' + statusWindowId + ' .window-content');
  if (!$content.length) {
    $content = createStatusWindow();
  }

  $content.html(buildTraxContent({
    worldly: trax.taboptions.worldly,
    activity: trax.taboptions.activity,
    combat: trax.taboptions.combat
  }));
  $content.css('font-size', currentFontSize + 'px');
  $content.find('span[style*="font-size:6px"]')
    .css('font-size', Math.max(4, currentFontSize * 0.4) + 'px');
}


