function populateCharacterTab() {

  const $char = $('#character');
  if (!$char.length) return;

  let trax = gwc.userdata.trax || {};

  $char.html(buildTraxContent({
    worldly: trax.taboptions.worldly,
    activity: trax.taboptions.activity,
    combat: trax.taboptions.combat
  }));
}
